async function supprimerMonCompte() {
  const phone = localStorage.getItem("userPhone");
  if (!phone) { showToast("❌ Tu n'es pas connecté", "error"); return; }
  if (!confirm(`⚠️ Supprimer définitivement ton compte ?\n\nNuméro : ${phone}\n\nToutes tes données seront effacées. Cette action est irréversible.`)) return;
  const confirme = prompt("Pour confirmer, tape SUPPRIMER :");
  if (confirme !== "SUPPRIMER") { showToast("❌ Suppression annulée", "info"); return; }

  // Supprimer de Turso
  if (turso) {
    try {
      await turso.execute({ sql: "DELETE FROM utilisateurs WHERE phone=?", args: [phone] });
      await turso.execute({ sql: "UPDATE users SET role='deleted', phone=? WHERE phone=?",
        args: ["deleted_" + Date.now(), phone] });
    } catch(e) {}
  }
  // Supprimer localStorage
  ["userPhone","userRole","userPseudo","isPremium","contribSpam_"+phone,"adminPwdHash"].forEach(k => localStorage.removeItem(k));
  showToast("✅ Compte supprimé — à bientôt !", "success");
  setTimeout(() => { updateProfilStatus(); showTab("accueil"); }, 1500);
}

// Fix 25 : _embeddedCfg null — fallback robuste
function getCfgSafe() {
  if (_embeddedCfg) return _embeddedCfg;
  // Tenter de relire depuis localStorage
  try {
    const raw = localStorage.getItem(_CFG_KEY);
    if (raw) return JSON.parse(_decodeFallback(raw));
  } catch(e) {}
  return null;
}

// Accéder à un champ de config (pour l'upload ZIP)
function _getCfg(key) {
  const cfg = getCfgSafe();
  return cfg ? (cfg[key] || null) : null;
}

// ========== PWA — MANIFEST DYNAMIQUE + ICÔNES + INSTALLATION ==========
// Le manifest.json est généré au runtime (Blob URL) car LearnUpr est un
// fichier HTML unique sans serveur de fichiers statiques séparé. Les icônes
// sont embarquées en base64 pour ne dépendre d'aucune ressource externe.
(function() {
  const ICON_192_B64 = "";
  const ICON_512_B64 = "";

  const manifest = {
    name: "LearnUpr — Lycée du Manengouba",
    short_name: "LearnUpr",
    description: "Plateforme éducative pour les élèves du Lycée du Manengouba (Nkongsamba)",
    start_url: window.location.href.split("#")[0],
    scope: window.location.href.split("#")[0].replace(/\/[^/]*$/, "/"),
    display: "standalone",
    orientation: "portrait-primary",
    background_color: "#2E1065",
    theme_color: "#2E1065",
    icons: [
      { src: "data:image/png;base64," + ICON_192_B64, sizes: "192x192", type: "image/png", purpose: "any maskable" },
      { src: "data:image/png;base64," + ICON_512_B64, sizes: "512x512", type: "image/png", purpose: "any maskable" }
    ]
  };

  const manifestBlob = new Blob([JSON.stringify(manifest)], { type: "application/json" });
  const manifestUrl = URL.createObjectURL(manifestBlob);

  const manifestLink = document.getElementById("learnupr-manifest-link");
  if (manifestLink) manifestLink.setAttribute("href", manifestUrl);

  const favicon = document.getElementById("learnupr-favicon");
  if (favicon) favicon.setAttribute("href", "data:image/png;base64," + ICON_192_B64);

  const appleIcon = document.getElementById("learnupr-apple-icon");
  if (appleIcon) appleIcon.setAttribute("href", "data:image/png;base64," + ICON_192_B64);

  // ── Bouton d'installation natif (Android/Chrome/Edge) ──
  // Affiché uniquement si :
  //  1) toutes les conditions techniques de l'installabilité sont remplies
  //     (le navigateur déclenche alors "beforeinstallprompt")
  //  2) l'app n'a pas déjà été installée via ce flux auparavant
  //     (persisté en localStorage pour ne pas réafficher le bouton aux
  //     visites suivantes même si le navigateur réémettait l'événement)
  let _deferredInstallPrompt = null;
  const _INSTALL_FLAG = "learnupr_pwa_installee";

  window.addEventListener("beforeinstallprompt", (e) => {
    e.preventDefault();
    if (localStorage.getItem(_INSTALL_FLAG) === "1") return; // déjà installée, on ne ré-affiche pas
    _deferredInstallPrompt = e;
    const btn = document.getElementById("btnInstallApp");
    if (btn) btn.style.display = "flex";
  });

  window._lancerInstallationPWA = async function() {
    if (!_deferredInstallPrompt) {
      showToast("ℹ️ Utilise le menu de ton navigateur → \"Ajouter à l'écran d'accueil\"", "info");
      return;
    }
    _deferredInstallPrompt.prompt();
    const { outcome } = await _deferredInstallPrompt.userChoice;
    if (outcome === "accepted") {
      localStorage.setItem(_INSTALL_FLAG, "1");
      showToast("✅ LearnUpr installé !", "success");
      const btn = document.getElementById("btnInstallApp");
      if (btn) btn.style.display = "none";
    }
    _deferredInstallPrompt = null;
  };

  window.addEventListener("appinstalled", () => {
    localStorage.setItem(_INSTALL_FLAG, "1");
    const btn = document.getElementById("btnInstallApp");
    if (btn) btn.style.display = "none";
    showToast("🎉 LearnUpr est maintenant installé sur ton appareil !", "success");
  });
})();

// ========== SERVICE WORKER — MODE HORS LIGNE COMPLET ==========
(function() {
  if (!('serviceWorker' in navigator)) return;

  // ─── Code du Service Worker ───────────────────────────────────────────────
  // Stratégies :
  //  • Shell (ce fichier HTML)       → Cache-First  (app disponible hors ligne)
  //  • Assets CDN (polices, pdf.js…) → Stale-While-Revalidate (rapide + frais)
  //  • Contenus Cloudinary (PDF/docs)→ Cache-First  (lecture offline après 1ère ouverture)
  //  • API Turso / Gemini / divers   → Network-Only (données dynamiques, pas de cache)
  const SW_CODE = `
const CACHE_SHELL   = 'learnupr-shell-v1';
const CACHE_ASSETS  = 'learnupr-assets-v1';
const CACHE_CONTENT = 'learnupr-content-v1';

// Assets CDN à pré-cacher au premier install
const PRECACHE_ASSETS = [
  'https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;600;700;800&family=Inter:wght@400;500;600;700;800&display=swap',
  'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js',
  'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js',
  'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js'
];

// ── Install : pré-cacher le shell et les assets CDN ──────────────────────
self.addEventListener('install', e => {
  e.waitUntil((async () => {
    // 1. Shell : mettre en cache la page HTML elle-même
    const shellCache = await caches.open(CACHE_SHELL);
    try {
      await shellCache.add(new Request(self.location.origin + '/', { cache: 'reload' }));
    } catch(_) {}

    // 2. Assets CDN : best-effort (ne bloque pas l'install si réseau KO)
    const assetCache = await caches.open(CACHE_ASSETS);
    await Promise.allSettled(
      PRECACHE_ASSETS.map(url =>
        fetch(url).then(r => { if (r.ok) assetCache.put(url, r); }).catch(() => {})
      )
    );
    self.skipWaiting();
  })());
});

// ── Activate : nettoyer les anciens caches ────────────────────────────────
self.addEventListener('activate', e => {
  const KEPT = [CACHE_SHELL, CACHE_ASSETS, CACHE_CONTENT];
  e.waitUntil(
    caches.keys().then(keys =>
      Promise.all(keys.filter(k => !KEPT.includes(k)).map(k => caches.delete(k)))
    ).then(() => self.clients.claim())
  );
});

// ── Fetch : routage par stratégie ─────────────────────────────────────────
self.addEventListener('fetch', e => {
  const req = e.request;
  const url = req.url;

  // Ignorer les requêtes non-GET
  if (req.method !== 'GET') return;

  // ── API dynamiques → Network-Only (jamais en cache) ──────────────────
  if (
    url.includes('turso.io') ||
    url.includes('libsql') ||
    url.includes('generativelanguage.googleapis.com') || // Gemini
    url.includes('fonts.gstatic.com')                    // binaires polices (lourds, gérés par le browser)
  ) {
    return; // laisser le navigateur gérer sans interception
  }

  // ── Shell HTML → Cache-First ──────────────────────────────────────────
  if (url === self.registration.scope || url === self.registration.scope.replace(/\\/$/, '') ||
      url.startsWith(self.registration.scope) && !url.includes('.')) {
    e.respondWith((async () => {
      const cache = await caches.open(CACHE_SHELL);
      const cached = await cache.match(req);
      if (cached) {
        // Revalider en arrière-plan
        fetch(req).then(r => { if (r && r.ok) cache.put(req, r.clone()); }).catch(() => {});
        return cached;
      }
      try {
        const res = await fetch(req);
        if (res && res.ok) cache.put(req, res.clone());
        return res;
      } catch(_) {
        return cached || new Response('<h2>LearnUpr — mode hors ligne</h2><p>Rechargez quand vous serez connecté.</p>',
          { headers: { 'Content-Type': 'text/html; charset=utf-8' } });
      }
    })());
    return;
  }

  // ── Assets CDN (polices CSS, pdf.js, jszip) → Stale-While-Revalidate ─
  if (
    url.includes('fonts.googleapis.com') ||
    url.includes('cdnjs.cloudflare.com')
  ) {
    e.respondWith((async () => {
      const cache = await caches.open(CACHE_ASSETS);
      const cached = await cache.match(req);
      const networkFetch = fetch(req).then(r => {
        if (r && r.ok) cache.put(req, r.clone());
        return r;
      }).catch(() => null);
      return cached || networkFetch || new Response('', { status: 503 });
    })());
    return;
  }

  // ── Contenus Cloudinary (PDF, docx, images) → Cache-First ───────────
  if (url.includes('cloudinary.com') || url.includes('res.cloudinary')) {
    e.respondWith((async () => {
      const cache = await caches.open(CACHE_CONTENT);
      const cached = await cache.match(req);
      if (cached) return cached;
      try {
        const res = await fetch(req);
        if (res && res.ok) cache.put(req, res.clone());
        return res;
      } catch(_) {
        return new Response('', { status: 503 });
      }
    })());
    return;
  }
  // Tout le reste → réseau sans interception
});

// ── Message : forcer mise à jour du cache shell ───────────────────────────
self.addEventListener('message', e => {
  if (e.data === 'SKIP_WAITING') self.skipWaiting();
  if (e.data === 'CACHE_SHELL') {
    caches.open(CACHE_SHELL).then(c =>
      fetch(self.registration.scope, { cache: 'reload' }).then(r => { if (r.ok) c.put(self.registration.scope, r); }).catch(() => {})
    );
  }
});
`;

  try {
    const b64 = btoa(unescape(encodeURIComponent(SW_CODE)));
    const swDataUrl = 'data:application/javascript;base64,' + b64;
    navigator.serviceWorker.register(swDataUrl).then(reg => {
      console.info('✅ Service Worker LearnUpr actif (mode hors ligne)');

      // Notifier le SW de mettre en cache le shell après chaque chargement réussi
      if (reg.active) reg.active.postMessage('CACHE_SHELL');

      // Détecter une mise à jour disponible
      reg.addEventListener('updatefound', () => {
        const newWorker = reg.installing;
        newWorker.addEventListener('statechange', () => {
          if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
            // Nouvelle version disponible : on force la prise en compte immédiate
            newWorker.postMessage('SKIP_WAITING');
          }
        });
      });
    }).catch(() => {});
  } catch(e) {}
})();

// ========== FEAT 2 : RÉVISION EXPRESS ==========
function lancerRevisionExpress() {
  if (!checkPremium()) { openPremiumGate("revision"); return; }
  // Mélanger toutes les questions de toutes les matières
  const allBuiltIn = Object.values(QUIZ_QUESTIONS).flat();
  const allCustom = customQuizQuestions || [];
  const allQ = [...allBuiltIn, ...allCustom].sort(() => Math.random() - 0.5).slice(0, 10);

  if (allQ.length === 0) { showToast("❌ Aucune question disponible", "error"); return; }

  quizState.matiere = "";
  quizState.timerVal = 30;
  quizState.score = 0;
  quizState.current = 0;
  quizState.answered = false;
  quizState.label = "⚡ Révision Express";

  // Mélanger les choix de chaque question
  quizState.questions = allQ.map(q => {
    if (!q.c || !Array.isArray(q.c)) return q;
    const indices = [0,1,2,3].sort(() => Math.random() - 0.5);
    return { ...q, c: indices.map(i => q.c[i]), r: indices.indexOf(q.r) };
  });

  document.getElementById("quiz-home").style.display = "none";
  document.getElementById("quiz-result").style.display = "none";
  document.getElementById("quiz-game").style.display = "block";
  afficherQuestion();
  showToast("⚡ Révision Express démarrée !", "success");
}

